import { Component, OnInit } from '@angular/core';
import { AuthService } from '../../core/services/auth.service';
import { TeamService, DepartmentService, UserService } from '../../core/services/api.services';
import { ToastService } from '../../core/services/toast.service';
import { Team, Department, User } from '../../core/models';

@Component({ selector: 'app-teams', templateUrl: './teams.component.html' })
export class TeamsComponent implements OnInit {
  teams: Team[] = [];
  departments: Department[] = [];
  // Users shown in the lead picker — changes based on selected dept
  leadCandidates: User[] = [];
  loading = true;
  showForm = false;
  showDelConfirm = false;
  formMode: 'create' | 'edit' = 'create';
  selected: Team | null = null;
  saving = false;
  showMemberModal = false;
  memberCandidates: User[] = [];
  newMemberId: number | null = null;
  form: any = { name: '', departmentId: null, teamLeadId: null, description: '' };

  constructor(public auth: AuthService, private teamService: TeamService,
    private deptService: DepartmentService, private userService: UserService, private toast: ToastService) {}

  ngOnInit(): void {
    this.load();
    this.deptService.getAll().subscribe(r => { if (r.success) this.departments = r.data; });
  }

  load(): void {
    this.loading = true;
    const obs = this.auth.isDeptHead
      ? this.teamService.getByDept(this.auth.deptId)
      : this.teamService.getAll();
    obs.subscribe(r => {
      if (r.success) this.teams = r.data;
      this.loading = false;
    });
  }

  // When dept changes in the form, reload the lead candidates from that dept
  onDeptChange(): void {
    this.form.teamLeadId = null;
    this.loadLeadCandidates(this.form.departmentId);
  }

  loadLeadCandidates(deptId: number | null): void {
    if (!deptId) {
      // No dept selected — show all approved non-PM users
      this.userService.getAll().subscribe(r => {
        if (r.success) this.leadCandidates = r.data.filter(u =>
          u.approvalStatus === 'APPROVED' && u.role !== 'PROJECT_MANAGER');
      });
    } else {
      // Show all approved users in that dept
      this.userService.getByDept(deptId).subscribe(r => {
        if (r.success) this.leadCandidates = r.data.filter(u => u.approvalStatus === 'APPROVED');
      });
    }
  }

  openCreate(): void {
    this.formMode = 'create';
    this.form = {
      name: '', description: '',
      departmentId: this.auth.isDeptHead ? this.auth.deptId : null,
      teamLeadId: null
    };
    this.loadLeadCandidates(this.form.departmentId);
    this.showForm = true;
  }

  openEdit(t: Team): void {
    this.formMode = 'edit';
    this.selected = t;
    this.form = {
      name: t.name,
      description: t.description || '',
      departmentId: t.department?.id || null,
      teamLeadId: t.teamLead?.id || null
    };
    // Load all users from this team's dept as lead candidates
    this.loadLeadCandidates(this.form.departmentId);
    this.showForm = true;
  }

  save(): void {
    if (!this.form.name) return;
    this.saving = true;
    const payload = { ...this.form };
    const obs = this.formMode === 'create'
      ? this.teamService.create(payload)
      : this.teamService.update(this.selected!.id, payload);
    obs.subscribe({
      next: r => {
        this.saving = false;
        if (r.success) { 
          this.showForm = false; this.load(); 
          this.toast.showSuccess(this.formMode === 'create' ? 'Team created successfully' : 'Team updated successfully');
        } else { this.toast.showError(r.message || 'Failed to save team'); }
      },
      error: err => { this.saving = false; this.toast.showError(err.error?.message || 'Error saving team'); }
    });
  }

  confirmDelete(t: Team): void { this.selected = t; this.showDelConfirm = true; }
  doDelete(): void {
    this.teamService.delete(this.selected!.id).subscribe({
      next: r => {
        if (r.success) { 
          this.showDelConfirm = false; this.load(); 
          this.toast.showSuccess('Team deleted successfully');
        } else { this.toast.showError(r.message || 'Failed to delete team'); }
      },
      error: err => this.toast.showError(err.error?.message || 'Error deleting team')
    });
  }

  getLeadName(t: Team): string {
    return t.teamLead ? `${t.teamLead.firstName} ${t.teamLead.lastName}` : 'Unassigned';
  }

  openMemberModal(t: Team): void {
    this.selected = t;
    this.newMemberId = null;
    this.showMemberModal = true;

    const deptId = t.department?.id || (this.auth.isDeptHead ? this.auth.deptId : 0);
    if (deptId) {
      this.userService.getByDept(deptId).subscribe(r => {
        if (r.success) {
          // Filter to show only employees not already in THIS team
          this.memberCandidates = r.data.filter(u => u.team?.id !== t.id && u.role === 'EMPLOYEE');
        }
      });
    }
  }

  doAddMember(): void {
    if (!this.selected || !this.newMemberId) return;
    this.userService.update(this.newMemberId, { teamId: this.selected.id }).subscribe({
      next: r => {
        if (r.success) {
          this.showMemberModal = false;
          this.toast.showSuccess('Member added to team');
          this.load();
        } else { this.toast.showError(r.message || 'Failed to add member'); }
      },
      error: err => this.toast.showError(err.error?.message || 'Error adding member')
    });
  }
}
<div class="fade-in">
  <div class="page-header">
    <div>
      <div class="page-title">{{ auth.isDeptHead ? 'My Department Teams' : 'All Teams' }}</div>
      <div class="page-subtitle">{{ teams.length }} team{{ teams.length !== 1 ? 's' : '' }}</div>
    </div>
    <button class="btn btn-primary" (click)="openCreate()">+ New Team</button>
  </div>

  <div *ngIf="loading" class="loading-wrap"><div class="spinner"></div></div>

  <div *ngIf="!loading && teams.length === 0" class="card empty-state" style="padding:60px">
    <div class="empty-icon">⬡</div>
    <div class="empty-title">No teams found</div>
    <div class="empty-desc">Create a team to get started</div>
  </div>

  <div *ngIf="!loading && teams.length > 0" class="grid-cards">
    <div *ngFor="let t of teams" class="info-card">
      <div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:12px">
        <div style="display:flex;align-items:center;gap:10px">
          <div style="width:40px;height:40px;border-radius:10px;background:var(--accent-subtle);color:var(--accent);display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:700;flex-shrink:0">
            {{ t.name[0] }}
          </div>
          <div>
            <div style="font-weight:700;font-size:15px">{{ t.name }}</div>
            <div style="font-size:12px;color:var(--text-muted)">{{ getDeptName(t) }}</div>
          </div>
        </div>
        <div style="display:flex;gap:6px">
          <button class="btn btn-icon btn-sm" (click)="openEdit(t)" title="Edit">✏</button>
          <button *ngIf="auth.isPM" class="btn btn-icon btn-sm btn-danger-ghost" (click)="confirmDelete(t)" title="Delete">✕</button>
        </div>
      </div>

      <div *ngIf="t.description" style="font-size:13px;color:var(--text-secondary);margin-bottom:12px;line-height:1.5">
        {{ t.description }}
      </div>

      <div style="display:flex;align-items:center;gap:8px;padding:10px;background:var(--bg-hover);border-radius:var(--radius-sm)">
        <div class="avatar" style="width:28px;height:28px;font-size:11px">
          {{ t.teamLead ? t.teamLead.firstName[0] + t.teamLead.lastName[0] : '?' }}
        </div>
        <div>
          <div style="font-size:12px;color:var(--text-muted)">Team Lead</div>
          <div style="font-size:13px;font-weight:600">{{ getLeadName(t) }}</div>
        </div>
      </div>

      <div style="margin-top:16px;display:flex;justify-content:flex-end">
        <button class="btn btn-outline btn-sm" (click)="openMemberModal(t)">+ Add Member</button>
      </div>
    </div>
  </div>
</div>

<!-- Add Member Modal -->
<div class="modal-overlay" *ngIf="showMemberModal" (click)="showMemberModal=false">
  <div class="modal modal-md" (click)="$event.stopPropagation()">
    <div class="modal-header">
      <div class="modal-title">Add Member to {{ selected?.name }}</div>
      <button class="modal-close" (click)="showMemberModal=false">×</button>
    </div>
    <div class="modal-body">
      <p style="margin-bottom:15px;color:var(--text-muted)">Select an employee from the department to join this team.</p>

      <div class="form-group">
        <label class="form-label">Employee</label>
        <select class="form-control" [(ngModel)]="newMemberId">
          <option [ngValue]="null">Select employee...</option>
          <option *ngFor="let u of memberCandidates" [ngValue]="u.id">
            {{ u.firstName }} {{ u.lastName }} ({{ u.team ? 'In ' + u.team.name : 'Unassigned' }})
          </option>
        </select>
      </div>
    </div>
    <div class="modal-footer">
      <button class="btn btn-outline" (click)="showMemberModal=false">Cancel</button>
      <button class="btn btn-primary" (click)="doAddMember()" [disabled]="!newMemberId">Add to Team</button>
    </div>
  </div>
</div>

<!-- Form Modal -->
<div class="modal-overlay" *ngIf="showForm" (click)="showForm=false">
  <div class="modal" (click)="$event.stopPropagation()">
    <div class="modal-header">
      <div class="modal-title">{{ formMode === 'create' ? 'New Team' : 'Edit Team' }}</div>
      <button class="modal-close" (click)="showForm=false">×</button>
    </div>
    <div class="modal-body">
      <div class="form-group">
        <label class="form-label">Team Name *</label>
        <input class="form-control" [(ngModel)]="form.name" placeholder="e.g. Backend Team">
      </div>
      <div class="form-group">
        <label class="form-label">Description</label>
        <textarea class="form-control" [(ngModel)]="form.description" placeholder="What does this team work on?" rows="2"></textarea>
      </div>
      <div class="form-group" *ngIf="auth.isPM">
        <label class="form-label">Department</label>
        <select class="form-control" [(ngModel)]="form.departmentId" (ngModelChange)="onDeptChange()">
          <option [ngValue]="null">Select department...</option>
          <option *ngFor="let d of departments" [ngValue]="d.id">{{ d.name }}</option>
        </select>
      </div>
      <div class="form-group">
        <label class="form-label">Team Lead</label>
        <select class="form-control" [(ngModel)]="form.teamLeadId">
          <option [ngValue]="null">No lead assigned</option>
          <option *ngFor="let u of leadCandidates" [ngValue]="u.id">
            {{ u.firstName }} {{ u.lastName }} ({{ u.role }})
          </option>
        </select>
      </div>
    </div>
    <div class="modal-footer">
      <button class="btn btn-outline" (click)="showForm=false">Cancel</button>
      <button class="btn btn-primary" (click)="save()" [disabled]="saving || !form.name">
        {{ saving ? 'Saving...' : (formMode === 'create' ? 'Create Team' : 'Save Changes') }}
      </button>
    </div>
  </div>
</div>

<!-- Delete Confirm -->
<div class="modal-overlay" *ngIf="showDelConfirm" (click)="showDelConfirm=false">
  <div class="modal modal-sm" (click)="$event.stopPropagation()">
    <div class="modal-header"><div class="modal-title" style="color:var(--danger)">Delete Team</div></div>
    <div class="modal-body"><p>Delete "<strong>{{ selected?.name }}</strong>"? This cannot be undone.</p></div>
    <div class="modal-footer">
      <button class="btn btn-outline" (click)="showDelConfirm=false">Cancel</button>
      <button class="btn btn-danger" (click)="doDelete()">Delete</button>
    </div>
  </div>
</div>
